// Parse file list
const output = $input.item(0).json.stdout;
const files = output.split('\n').filter(f => f.trim() !== '' && !f.includes('_capture_log'));

const vaultPath = '~/Library/Mobile Documents/iCloud~md~obsidian/Documents/MyVault';

// Return array of file objects
return files.map(file => ({
  relativePath: file,
  fullPath: `${vaultPath}/Inbox/${file}`,
  fileName: file.split('/').pop()
}));

// Extract note content and metadata
const fileInfo = $input.item(0).json;
const content = $input.item(0).json.stdout;

// Parse frontmatter if exists
let frontmatter = {};
let bodyContent = content;

if (content.startsWith('---')) {
  const endOfFrontmatter = content.indexOf('---', 3);
  if (endOfFrontmatter > 0) {
    const frontmatterText = content.substring(3, endOfFrontmatter);
    bodyContent = content.substring(endOfFrontmatter + 3).trim();

    // Simple YAML parsing
    frontmatterText.split('\n').forEach(line => {
      const [key, ...valueParts] = line.split(':');
      if (key && valueParts.length) {
        frontmatter[key.trim()] = valueParts.join(':').trim();
      }
    });
  }
}

// Extract any existing tags
const existingTags = frontmatter.tags || '';
const wordCount = bodyContent.split(/\s+/).length;

// Create AI analysis prompt
const analysisPrompt = `Analyze this personal knowledge management note and provide intelligent categorization and connections.

Note Content:
${bodyContent}

Existing Tags: ${existingTags}

Provide your response in this JSON format:
{
  "summary": "2-3 sentence summary of the note",
  "mainTopics": ["array of 3-5 main topics/themes"],
  "suggestedTags": ["array of relevant tags for organization"],
  "noteType": "one of: fleeting, literature, permanent, project, area, resource",
  "paraCategory": "one of: project, area, resource, archive",
  "suggestedFolder": "recommended PARA folder path",
  "relatedConcepts": ["concepts that should link to other notes"],
  "actionItems": ["any tasks or todos mentioned"],
  "questions": ["any questions raised that need answering"],
  "confidence": 0.0-1.0
}`;

return {
  fileInfo,
  content,
  bodyContent,
  frontmatter,
  wordCount,
  analysisPrompt
};

