// Parse AI analysis
const claudeResponse = $input.item(0).json;
const noteData = $input.item(0).json;

const analysisText = claudeResponse.content[0].text;
const analysis = JSON.parse(analysisText);

return {
  ...noteData,
  analysis
};

// Find related notes based on AI-identified concepts
const noteData = $input.item(0).json;
const analysis = noteData.analysis;
const existingNotesOutput = $input.item(1).json.stdout;

const existingNotes = existingNotesOutput.split('\n')
  .filter(f => f.trim() !== '')
  .map(f => f.replace('./', '').replace('.md', ''));

// Find potential links
const potentialLinks = [];
const relatedConcepts = analysis.relatedConcepts || [];

relatedConcepts.forEach(concept => {
  const conceptLower = concept.toLowerCase();
  existingNotes.forEach(note => {
    const noteLower = note.toLowerCase();
    if (noteLower.includes(conceptLower) || conceptLower.includes(noteLower)) {
      potentialLinks.push({
        concept,
        notePath: note
      });
    }
  });
});

// Also check main topics
analysis.mainTopics.forEach(topic => {
  const topicLower = topic.toLowerCase();
  existingNotes.forEach(note => {
    const noteLower = note.toLowerCase();
    if (noteLower.includes(topicLower)) {
      potentialLinks.push({
        concept: topic,
        notePath: note
      });
    }
  });
});

// Remove duplicates
const uniqueLinks = [...new Map(potentialLinks.map(item => 
  [item.notePath, item]
)).values()];

return {
  ...noteData,
  potentialLinks: uniqueLinks
};

// Create enhanced note with AI insights
const noteData = $input.item(0).json;
const analysis = noteData.analysis;
const links = noteData.potentialLinks || [];

const vaultPath = '~/Library/Mobile Documents/iCloud~md~obsidian/Documents/MyVault';
const destinationFolder = `${vaultPath}/${analysis.suggestedFolder}`;
const newFileName = noteData.fileInfo.fileName;

// Build enhanced note content
const enhancedContent = `---
processed: ${new Date().toISOString()}
tags: [${analysis.suggestedTags.join(', ')}]
type: ${analysis.noteType}
para: ${analysis.paraCategory}
ai_summary: "${analysis.summary}"
ai_confidence: ${analysis.confidence}
---

# ${newFileName.replace('.md', '').replace(/^\d{8}-\d{6}-/, '')}

## AI Summary
${analysis.summary}

## Original Content
${noteData.bodyContent}

---

## AI-Identified Topics
${analysis.mainTopics.map(topic => `- ${topic}`).join('\n')}

${analysis.actionItems && analysis.actionItems.length > 0 ? `## Action Items\n${analysis.actionItems.map(item => `- [ ] ${item}`).join('\n')}\n` : ''}

${analysis.questions && analysis.questions.length > 0 ? `## Questions to Explore\n${analysis.questions.map(q => `- ${q}`).join('\n')}\n` : ''}

## Related Notes
${links.length > 0 ? links.map(link => `- [[${link.notePath}]] - ${link.concept}`).join('\n') : '_No related notes found_'}

---
_Processed automatically by AI on ${new Date().toLocaleDateString()}_
`;

return {
  noteData,
  analysis,
  destinationFolder,
  newFilePath: `${destinationFolder}/${newFileName}`,
  enhancedContent,
  links
};

